    public sealed class TypedSubscriptionBuilder
    {
        private readonly IDbConnection conn;
        private Action<SubscriptionEventContext>? Applied;
        private Action<ErrorContext, Exception>? Error;
        private readonly List<string> querySqls = new();

        internal TypedSubscriptionBuilder(IDbConnection conn, Action<SubscriptionEventContext>? applied, Action<ErrorContext, Exception>? error)
        {
            this.conn = conn;
            Applied = applied;
            Error = error;
        }

        public TypedSubscriptionBuilder OnApplied(Action<SubscriptionEventContext> callback)
        {
            Applied += callback;
            return this;
        }

        public TypedSubscriptionBuilder OnError(Action<ErrorContext, Exception> callback)
        {
            Error += callback;
            return this;
        }

        public TypedSubscriptionBuilder AddQuery<TRow>(Func<QueryBuilder, global::SpacetimeDB.IQuery<TRow>> build)
        {
            var qb = new QueryBuilder();
            querySqls.Add(build(qb).ToSql());
            return this;
        }

        public SubscriptionHandle Subscribe() => new(conn, Applied, Error, querySqls.ToArray());
    }

    public abstract partial class Reducer
    {
        private Reducer() { }
    }

    public abstract partial class Procedure
    {
        private Procedure() { }
    }

    public sealed class DbConnection : DbConnectionBase<DbConnection, RemoteTables, Reducer>
    {
        public override RemoteTables Db { get; }
        public readonly RemoteReducers Reducers;
        public readonly RemoteProcedures Procedures;

        public DbConnection()
        {
            Db = new(this);
            Reducers = new(this);
            Procedures = new(this);
        }

        protected override IEventContext ToEventContext(Event<Reducer> Event) =>
        new EventContext(this, Event);

        protected override IReducerEventContext ToReducerEventContext(ReducerEvent<Reducer> reducerEvent) =>
        new ReducerEventContext(this, reducerEvent);

        protected override ISubscriptionEventContext MakeSubscriptionEventContext() =>
        new SubscriptionEventContext(this);

        protected override IErrorContext ToErrorContext(Exception exception) =>
        new ErrorContext(this, exception);

        protected override IProcedureEventContext ToProcedureEventContext(ProcedureEvent procedureEvent) =>
        new ProcedureEventContext(this, procedureEvent);

        protected override bool Dispatch(IReducerEventContext context, Reducer reducer)
        {
            var eventContext = (ReducerEventContext)context;
            return reducer switch
            {
                Reducer.AcceptFriendRequest args => Reducers.InvokeAcceptFriendRequest(eventContext, args),
                Reducer.AdminUnlistServer args => Reducers.InvokeAdminUnlistServer(eventContext, args),
                Reducer.ApproveJoinRequest args => Reducers.InvokeApproveJoinRequest(eventContext, args),
                Reducer.BanMember args => Reducers.InvokeBanMember(eventContext, args),
                Reducer.BlockUser args => Reducers.InvokeBlockUser(eventContext, args),
                Reducer.CancelJoinRequest args => Reducers.InvokeCancelJoinRequest(eventContext, args),
                Reducer.CleanupExpiredInvites args => Reducers.InvokeCleanupExpiredInvites(eventContext, args),
                Reducer.CreateChannel args => Reducers.InvokeCreateChannel(eventContext, args),
                Reducer.CreateInvite args => Reducers.InvokeCreateInvite(eventContext, args),
                Reducer.CreateServer args => Reducers.InvokeCreateServer(eventContext, args),
                Reducer.DeclineFriendRequest args => Reducers.InvokeDeclineFriendRequest(eventContext, args),
                Reducer.DeclineJoinRequest args => Reducers.InvokeDeclineJoinRequest(eventContext, args),
                Reducer.DeleteChannel args => Reducers.InvokeDeleteChannel(eventContext, args),
                Reducer.DeleteChannelSection args => Reducers.InvokeDeleteChannelSection(eventContext, args),
                Reducer.DeleteDirectMessage args => Reducers.InvokeDeleteDirectMessage(eventContext, args),
                Reducer.DeleteInvite args => Reducers.InvokeDeleteInvite(eventContext, args),
                Reducer.DeleteMessage args => Reducers.InvokeDeleteMessage(eventContext, args),
                Reducer.DeleteServer args => Reducers.InvokeDeleteServer(eventContext, args),
                Reducer.EditDirectMessage args => Reducers.InvokeEditDirectMessage(eventContext, args),
                Reducer.EditMessage args => Reducers.InvokeEditMessage(eventContext, args),
                Reducer.JoinDiscoverableServer args => Reducers.InvokeJoinDiscoverableServer(eventContext, args),
                Reducer.JoinDmVoice args => Reducers.InvokeJoinDmVoice(eventContext, args),
                Reducer.JoinVoiceChannel args => Reducers.InvokeJoinVoiceChannel(eventContext, args),
                Reducer.KickMember args => Reducers.InvokeKickMember(eventContext, args),
                Reducer.LeaveDmVoice args => Reducers.InvokeLeaveDmVoice(eventContext, args),
                Reducer.LeaveServer args => Reducers.InvokeLeaveServer(eventContext, args),
                Reducer.LeaveVoiceChannel args => Reducers.InvokeLeaveVoiceChannel(eventContext, args),
                Reducer.MarkChannelRead args => Reducers.InvokeMarkChannelRead(eventContext, args),
                Reducer.MarkDmRead args => Reducers.InvokeMarkDmRead(eventContext, args),
                Reducer.MoveChannel args => Reducers.InvokeMoveChannel(eventContext, args),
                Reducer.MoveChannelRelative args => Reducers.InvokeMoveChannelRelative(eventContext, args),
                Reducer.MoveChannelTo args => Reducers.InvokeMoveChannelTo(eventContext, args),
                Reducer.RegisterUser args => Reducers.InvokeRegisterUser(eventContext, args),
                Reducer.RemoveFriend args => Reducers.InvokeRemoveFriend(eventContext, args),
                Reducer.RemoveTimeout args => Reducers.InvokeRemoveTimeout(eventContext, args),
                Reducer.RenameServer args => Reducers.InvokeRenameServer(eventContext, args),
                Reducer.RequestToJoin args => Reducers.InvokeRequestToJoin(eventContext, args),
                Reducer.RespondDmServerInvite args => Reducers.InvokeRespondDmServerInvite(eventContext, args),
                Reducer.SendDirectMessage args => Reducers.InvokeSendDirectMessage(eventContext, args),
                Reducer.SendDmServerInvite args => Reducers.InvokeSendDmServerInvite(eventContext, args),
                Reducer.SendFriendRequest args => Reducers.InvokeSendFriendRequest(eventContext, args),
                Reducer.SendFriendRequestByUsername args => Reducers.InvokeSendFriendRequestByUsername(eventContext, args),
                Reducer.SendMessage args => Reducers.InvokeSendMessage(eventContext, args),
                Reducer.SetArchiveServiceIdentity args => Reducers.InvokeSetArchiveServiceIdentity(eventContext, args),
                Reducer.SetChannelSection args => Reducers.InvokeSetChannelSection(eventContext, args),
                Reducer.SetMemberRole args => Reducers.InvokeSetMemberRole(eventContext, args),
                Reducer.SetPresenceOffline args => Reducers.InvokeSetPresenceOffline(eventContext, args),
                Reducer.SetServerDiscovery args => Reducers.InvokeSetServerDiscovery(eventContext, args),
                Reducer.SetServerIcon args => Reducers.InvokeSetServerIcon(eventContext, args),
                Reducer.SetServerInvitePolicy args => Reducers.InvokeSetServerInvitePolicy(eventContext, args),
                Reducer.SetServerTags args => Reducers.InvokeSetServerTags(eventContext, args),
                Reducer.SetSpaceCreatePolicy args => Reducers.InvokeSetSpaceCreatePolicy(eventContext, args),
                Reducer.SetTypingState args => Reducers.InvokeSetTypingState(eventContext, args),
                Reducer.SetUserAdmin args => Reducers.InvokeSetUserAdmin(eventContext, args),
                Reducer.TimeoutMember args => Reducers.InvokeTimeoutMember(eventContext, args),
                Reducer.TouchPresence args => Reducers.InvokeTouchPresence(eventContext, args),
                Reducer.TransferOwnership args => Reducers.InvokeTransferOwnership(eventContext, args),
                Reducer.UnbanMember args => Reducers.InvokeUnbanMember(eventContext, args),
                Reducer.UnblockUser args => Reducers.InvokeUnblockUser(eventContext, args),
                Reducer.UpdateChannel args => Reducers.InvokeUpdateChannel(eventContext, args),
                Reducer.UpdateDmVoiceState args => Reducers.InvokeUpdateDmVoiceState(eventContext, args),
                Reducer.UpdateProfile args => Reducers.InvokeUpdateProfile(eventContext, args),
                Reducer.UpdateVoiceState args => Reducers.InvokeUpdateVoiceState(eventContext, args),
                Reducer.UseInvite args => Reducers.InvokeUseInvite(eventContext, args),
                _ => throw new ArgumentOutOfRangeException("Reducer", $"Unknown reducer {reducer}")
            };
        }

        public SubscriptionBuilder SubscriptionBuilder() => new(this);
        public event Action<ReducerEventContext, Exception> OnUnhandledReducerError
        {
            add => Reducers.InternalOnUnhandledReducerError += value;
            remove => Reducers.InternalOnUnhandledReducerError -= value;
        }
    }
